  connection_state = 'disconnected',
  lifecycle_state = 'active',
  runtime_state = 'idle',
  updated_at = '2026-03-22 06:30:00+08'
where tenant_id = '00000000-0000-0000-0000-000000000001'
  and id = '00000000-0000-0000-0000-000000000424';
